SELECT bs."in.comstock_building_type" AS comstock_building_type, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.electricity.total.energy_consumption..kwh" * bs.weight) AS "electricity.total.energy_consumption..kwh__baseline", sum(up."out.electricity.total.energy_consumption..kwh" * bs.weight) AS "electricity.total.energy_consumption..kwh__upgrade", sum((coalesce(bs."out.electricity.total.energy_consumption..kwh", 0) - coalesce(up."out.electricity.total.energy_consumption..kwh", 0)) * bs.weight) AS "electricity.total.energy_consumption..kwh__savings", sum(bs."out.natural_gas.total.energy_consumption..kwh" * bs.weight) AS "natural_gas.total.energy_consumption..kwh__baseline", sum(up."out.natural_gas.total.energy_consumption..kwh" * bs.weight) AS "natural_gas.total.energy_consumption..kwh__upgrade", sum((coalesce(bs."out.natural_gas.total.energy_consumption..kwh", 0) - coalesce(up."out.natural_gas.total.energy_consumption..kwh", 0)) * bs.weight) AS "natural_gas.total.energy_consumption..kwh__savings" FROM comstock_amy2018_r2_2025_md_agg_by_state_and_county_parquet AS bs JOIN comstock_amy2018_r2_2025_md_agg_by_state_and_county_parquet AS up ON bs.bldg_id = up.bldg_id AND bs.county = up.county AND bs.state = up.state AND bs.upgrade = 0 AND up.upgrade = 1 AND up.applicability = true WHERE bs.applicability = true AND bs.upgrade = 0 AND bs.state IN ('CO', 'NM') AND (bs.bldg_id, bs.county, bs.state) IN (SELECT bs.bldg_id, bs.county, bs.state FROM comstock_amy2018_r2_2025_md_agg_by_state_and_county_parquet AS bs WHERE bs.upgrade IN (1, 2) AND bs.applicability = true GROUP BY bs.bldg_id, bs.county, bs.state HAVING count(distinct(bs.upgrade)) = 2) GROUP BY 1 ORDER BY 1